1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export interface QuoteResult {
41	  premium: number;
42	}
43	
44	export interface ClaimResult {
45	  payout: number;
46	  remainingCap: number;
47	}
48	
49	export type Result = QuoteResult | ClaimResult;
50	
51	export interface ScenarioResult {
52	  results: Result[];
53	}
54	
55	const BASE_PREMIUM: Record<string, number> = {
56	  sword: 100,
57	  amulet: 60,
58	  staff: 80,
59	  potion: 40,
60	  rune: 25,
61	};
62	
63	const COMPONENT_PRICE = 25;
64	const BLOCK_SIZE = 3;
65	const BLOCK_PRICE = 60;
66	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
67	
68	const INSURANCE_VALUE: Record<string, number> = {
69	  sword: 1000,
70	  amulet: 600,
71	  staff: 800,
72	  potion: 400,
73	};
74	const COMPONENT_INSURANCE_VALUE = 250;
75	
76	const DEDUCTIBLE = 100;
77	const CAP_MULTIPLIER = 2;
78	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
79	const REIMBURSEMENT_HALF_RATE = 0.5;
80	
81	const INITIAL_ASSESSMENT_RATE = 0.1;
82	const CURSE_SURCHARGE_RATE = 0.5;
83	const HIGH_ENCHANTMENT_RATE = 0.3;
84	const HIGH_ENCHANTMENT_THRESHOLD = 5;
85	const LOYALTY_DISCOUNT_RATE = 0.2;
86	const LOYALTY_YEARS_THRESHOLD = 2;
87	const FOLLOWUP_DISCOUNT_RATE = 0.15;
88	const PROCESSING_FEE = 5;
89	const FLOAT_PRECISION_DIGITS = 6;
90	
91	const itemOwnBase = (item: Item): number => {
92	  return COMPONENT_TYPES.has(item.type)
93	    ? COMPONENT_PRICE
94	    : BASE_PREMIUM[item.type];
95	};
96	
97	const itemSurcharge = (item: Item): number => {
98	  const own = itemOwnBase(item);
99	  const curse = item.cursed ? CURSE_SURCHARGE_RATE * own : 0;
100	  const highEnchantment =
101	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
102	      ? HIGH_ENCHANTMENT_RATE * own
103	      : 0;
104	  return curse + highEnchantment;
105	};
106	
107	const componentBase = (count: number): number => {
108	  return count === BLOCK_SIZE ? BLOCK_PRICE : count * COMPONENT_PRICE;
109	};
110	
111	const countByType = (items: Item[]): Map<string, number> => {
112	  const counts = new Map<string, number>();
113	  for (const item of items) {
114	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
115	  }
116	  return counts;
117	};
118	
119	const itemBaseTotal = (items: Item[]): number => {
120	  let total = 0;
121	  for (const [type, count] of countByType(items)) {
122	    total += COMPONENT_TYPES.has(type)
123	      ? componentBase(count)
124	      : BASE_PREMIUM[type] * count;
125	  }
126	  return total;
127	};
128	
129	const quotePremium = (
130	  step: QuoteStep,
131	  customer: Customer,
132	  isFollowUp: boolean,
133	): number => {
134	  const policyBase = itemBaseTotal(step.items);
135	  const surcharges = step.items.reduce(
136	    (sum, item) => sum + itemSurcharge(item),
137	    0,
138	  );
139	  const initialAssessment = INITIAL_ASSESSMENT_RATE * policyBase;
140	  const loyaltyDiscount =
141	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
142	      ? LOYALTY_DISCOUNT_RATE * policyBase
143	      : 0;
144	  const followUpDiscount = isFollowUp ? FOLLOWUP_DISCOUNT_RATE * policyBase : 0;
145	  const premium =
146	    policyBase +
147	    surcharges +
148	    initialAssessment -
149	    loyaltyDiscount -
150	    followUpDiscount +
151	    PROCESSING_FEE;
152	  return Math.ceil(Number(premium.toFixed(FLOAT_PRECISION_DIGITS)));
153	};
154	
155	interface Policy {
156	  items: Item[];
157	  remainingCap: number;
158	}
159	
160	const itemInsuranceValue = (item: Item): number => {
161	  return COMPONENT_TYPES.has(item.type)
162	    ? COMPONENT_INSURANCE_VALUE
163	    : INSURANCE_VALUE[item.type];
164	};
165	
166	const insuranceSum = (items: Item[]): number => {
167	  return items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
168	};
169	
170	const reimbursable = (amount: number, item: Item): number => {
171	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
172	    ? REIMBURSEMENT_HALF_RATE * amount
173	    : amount;
174	};
175	
176	const damagePayout = (damage: Damage, items: Item[]): number => {
177	  const item = items.find((candidate) => candidate.type === damage.itemType);
178	  return Math.max(0, reimbursable(damage.amount, item!) - DEDUCTIBLE);
179	};
180	
181	const claimResult = (step: ClaimStep, policies: Policy[]): ClaimResult => {
182	  const policy = policies[step.policy];
183	  const requested = step.incident.damages.reduce(
184	    (sum, damage) => sum + damagePayout(damage, policy.items),
185	    0,
186	  );
187	  const payout = Math.min(requested, policy.remainingCap);
188	  policy.remainingCap -= payout;
189	  return { payout, remainingCap: policy.remainingCap };
190	};
191	
192	export const runScenario = (scenario: Scenario): ScenarioResult => {
193	  const policies: Policy[] = [];
194	  let quotesSeen = 0;
195	  const results = scenario.steps.map((step, index): Result => {
196	    if (step.op === "claim") {
197	      return claimResult(step, policies);
198	    }
199	    const isFollowUp = quotesSeen >= 1;
200	    quotesSeen += 1;
201	    policies[index] = {
202	      items: step.items,
203	      remainingCap: CAP_MULTIPLIER * insuranceSum(step.items),
204	    };
205	    return { premium: quotePremium(step, scenario.customer, isFollowUp) };
206	  });
207	  return { results };
208	};
